<style scoped>



svg {
  width: 100%;
  height: auto;
    --dash: 150;
}



svg path {
  fill: transparent;
  stroke: black;
  stroke-width: 1;

  stroke-dasharray: var(--dash);
  stroke-dashoffset: var(--dash);

  animation: drawText 4s linear forwards;
}

/* slowly draws outline then fills */
@keyframes drawText {
  0% {
